        // Explications par élément
        ["clean.explain.d3d8"]     = ["GenTool (proxy DirectX 8 dans le dossier du jeu). Le retirer = le jeu retombe sur le DirectX 8 de Windows (vérifié automatiquement après nettoyage) ; seules les fonctions GenTool sont perdues. Conseillé : Désactiver (réversible).",
                                      "GenTool (DirectX 8 proxy in the game folder). Removing it = the game falls back to Windows' own DirectX 8 (verified automatically after cleanup); only GenTool features are lost. Recommended: Disable (reversible)."],
        ["clean.dx.checking"]   = ["🔎 Vérification du DirectX 8 système (celui de Windows)…", "🔎 Checking the system DirectX 8 (Windows' own)…"],
        ["clean.dx.ok"]         = ["DirectX 8 d'origine Windows vérifié — le jeu est bon. ({0})", "Genuine Windows DirectX 8 verified — the game is fine. ({0})"],
        ["clean.dx.bad"]        = ["DirectX 8 système anormal : {0}", "System DirectX 8 looks abnormal: {0}"],
        ["clean.dx.sfc.ask"]    = ["Le DirectX 8 de Windows semble anormal. Lancer la réparation officielle de Windows (« sfc /scannow ») ?\n\n⚠ C'est LA méthode sûre (aucun téléchargement), mais ça peut être LONG (souvent 5 à 20 minutes). Une fenêtre noire va s'ouvrir : laisse-la travailler jusqu'à 100 %.",
                                   "Windows' DirectX 8 looks abnormal. Launch Windows' official repair (“sfc /scannow”)?\n\n⚠ This is THE safe method (no download), but it can take a WHILE (often 5–20 minutes). A black window will open: let it run to 100%."],
        ["clean.dx.sfc.started"] = ["🛠 Réparation Windows lancée (sfc /scannow) — laisse la fenêtre aller jusqu'à 100 %.", "🛠 Windows repair started (sfc /scannow) — let the window reach 100%."],
        ["clean.log.saved"]      = ["📄 Journal enregistré : {0}", "📄 Log saved: {0}"],
        ["clean.explain.gentool"]  = ["Composant GenTool. Sans danger à retirer (sauvegarde recommandée).", "GenTool component. Safe to remove (backup recommended)."],
        ["clean.explain.d3d8cfg"]  = ["Config GenTool (d3d8.cfg) : réécrite à chaque session de jeu. Sans danger à retirer ; le jeu la recrée si GenTool est encore là.",
                                      "GenTool config (d3d8.cfg): rewritten every game session. Safe to remove; the game recreates it if GenTool is still present."],
        ["clean.explain.gentoolupdater"] = ["Auto-updater de GenTool (déposé dans le dossier du jeu et dans %TEMP%). Sans danger à retirer ; il revient à la prochaine mise à jour de GenTool.",
                                      "GenTool auto-updater (dropped in the game folder and in %TEMP%). Safe to remove; it comes back on GenTool's next update."],
        ["clean.explain.restorebak"] = ["Remet l'original que GenPatcher/GenTool avait sauvegardé en « .bak » avant de le patcher (Game.dat, BrowserEngine.dll, WindowZH.big…). C'est le « dé-patch » que ces outils n'offrent pas. La version patchée actuelle est sauvegardée avant. Note : si GenTool/GenPatcher est encore actif, il pourra re-patcher à la prochaine session.",
                                      "Restores the original that GenPatcher/GenTool had backed up as “.bak” before patching it (Game.dat, BrowserEngine.dll, WindowZH.big…). This is the “un-patch” those tools don't offer. The current patched version is backed up first. Note: if GenTool/GenPatcher is still active, it may re-patch on the next session."],
        ["clean.explain.restoreglr"] = ["Fichiers renommés « .GLR » par GenLauncher pendant une partie et JAMAIS remis en place (résidu d'un plantage/fermeture forcée). Les restaurer rend au jeu sa control bar / ses hotkeys / ses fichiers. Sans danger — c'est une simple remise du nom d'origine.",
                                      "Files renamed “.GLR” by GenLauncher during a game and NEVER restored (leftover from a crash/forced close). Restoring them gives the game back its control bar / hotkeys / files. Safe — it just renames them back."],
        ["clean.explain.gpaddon"]  = ["Contenu additionnel posé par GenPatcher (Control Bar Pro, hotkeys, décals, maps custom). Re-installable via GenPatcher. Reste dans le dossier après une désinstallation Steam (Steam ne connaît pas ces fichiers).",
                                      "Add-on content installed by GenPatcher (Control Bar Pro, hotkeys, decals, custom maps). Re-installable via GenPatcher. Stays in the folder after a Steam uninstall (Steam doesn't know these files)."],
        ["clean.explain.edgescroller"] = ["EdgeScroller (défilement caméra en mode fenêtré, posé par GenPatcher). Sans danger à retirer.",
                                      "EdgeScroller (edge camera scrolling in window mode, installed by GenPatcher). Safe to remove."],
        ["clean.explain.gplog"]    = ["Journal technique laissé par le jeu/GenPatcher. Inoffensif à retirer.",
                                      "Technical log left by the game/GenPatcher. Harmless to remove."],
        ["clean.explain.gpbak"]    = ["Sauvegarde « .bak » d'un fichier que GenPatcher a DÉSACTIVÉ (l'original neutralisé pour corriger un bug). En désinstallation totale, sans danger à retirer.",
                                      "“.bak” backup of a file GenPatcher DISABLED (original neutralized to fix a bug). In a full uninstall, safe to remove."],
        ["clean.explain.gl7z"]     = ["Bibliothèque 7-Zip déposée par GenLauncher (sous-dossiers x64/x86). Sans danger à retirer.",
                                      "7-Zip library dropped by GenLauncher (x64/x86 subfolders). Safe to remove."],
        ["clean.explain.gentoolmaps"] = ["Maps de classement (« [RANK] » / « [NMC] ») que GenTool télécharge et met à jour TOUT SEUL dans tes Documents. Les retirer ne touche PAS à tes propres maps. Sans danger : GenTool les re-télécharge au besoin. Utile car elles changent hors de ton contrôle (source de divergence entre joueurs).",
                                      "Ladder maps (“[RANK]” / “[NMC]”) that GenTool downloads and updates ON ITS OWN in your Documents. Removing them does NOT touch your own maps. Safe: GenTool re-downloads them when needed. Handy because they change outside your control (a source of divergence between players)."],
        ["clean.explain.dbghelp"]  = ["Gestionnaire de crash (GenTool) ou DLL renommée par GenPatcher. À retirer avec précaution.", "Crash handler (GenTool) or DLL renamed by GenPatcher. Remove with care."],
